using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public static class ApiTool
{
    [McpServerTool, Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchApiData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to fetch (e.g. \"users/1\").")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");
        using var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(
            await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public static class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt that asks the model to summarize the given text.")]
    public static GetPromptResult Summarize(
        [Description("The text to summarize.")] string text,
        [Description("Optional target style: brief, detailed, or bullet-points.")] string? style = "brief")
    {
        return new GetPromptResult
        {
            Description = "Summarization prompt",
            Messages =
            [
                new PromptMessage
                {
                    Role = Role.User,
                    Content = new TextContentBlock
                    {
                        Text = $"""
                            Please summarize the following text.
                            Style: {style}

                            ---
                            {text}
                            ---
                            """
                    }
                }
            ]
        };
    }
}

